content.query:
let created = customMetrics
| where name == "cashflow.transactions.created"
| where timestamp {TimeRange}
| summarize Created = sum(valueSum) by bin(timestamp, 5m);
let processed = customMetrics
| where name == "cashflow.consolidation.events_processed"
| where timestamp {TimeRange}
| summarize Processed = sum(valueSum) by bin(timestamp, 5m);
created
| join kind=leftouter processed on timestamp
| extend Delta = Created - coalesce(Processed, 0)
| project timestamp, Created, Processed = coalesce(Processed, 0), Delta
| order by timestamp asc
